detailed_optimizations.code_changes:
在调用sparse_matvec()前对矩阵进行重排序：
1. 使用RCM（Reverse Cuthill-McKee）算法对矩阵行/列重排序
2. 对重排序后的矩阵重新生成CSR格式
3. 对x和y向量应用相同的置换

循环优化：
for (int i = 0; i < n; i += BLOCK_SIZE) {
    int i_end = min(i + BLOCK_SIZE, n);
    for (int ii = i; ii < i_end; ii++) {
        double sum = 0.0;
        for (int j = rowptr[ii]; j < rowptr[ii + 1]; j++) {
            sum += values[j] * x[colidx[j]];
        }
        y[ii] = sum;
    }
}

使用编译器内联汇编或intrinsics实现：
#pragma omp simd reduction(+:sum)
for (int j = rowptr[i]; j < rowptr[i + 1]; j++) {
    __builtin_prefetch(&x[colidx[j + PREFETCH_DISTANCE]], 0, 1);
    sum += values[j] * x[colidx[j]];
}

同时使用-ffast-math和-march=native编译选项

double sum0 = 0.0, sum1 = 0.0, sum2 = 0.0, sum3 = 0.0;
int i;
for (i = 0; i < n - 3; i += 4) {
    sum0 += x[i] * y[i];
    sum1 += x[i+1] * y[i+1];
    sum2 += x[i+2] * y[i+2];
    sum3 += x[i+3] * y[i+3];
}
double sum = sum0 + sum1 + sum2 + sum3;
for (; i < n; i++) {
    sum += x[i] * y[i];
}
return sum;

将sparse_matvec()和后续的dot_product()融合：
void fused_spmv_dot(int n, const int *rowptr, const int *colidx,
                    const double *values, const double *x, double *y, double *dot_result) {
    double sum_dot = 0.0;
    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        for (int j = rowptr[i]; j < rowptr[i + 1]; j++) {
            sum += values[j] * x[colidx[j]];
        }
        y[i] = sum;
        sum_dot += y[i] * y[i];  // 假设需要计算y·y
    }
    *dot_result = sum_dot;
}
